): Promise<PreparedToolCall | ImmediateToolCallOutcome> { // 1. 查找工具 — 模型调了个不存在的工具？ const tool = currentContext.tools?.find(t => t.name === toolCall.name); if (!tool) { return { kind: "immediate", result: createErrorToolResult( `Tool ${toolCall.name} not found` ), isError: true, }; } try { // 2. 参数验证 — 模型传了错误的参数格式？ const preparedToolCall = prepareToolCallArguments(tool, toolCall); const validatedArgs = validateToolArguments(tool, preparedToolCall); // 3. beforeToolCall 钩子 — 上层说不许执行？ if (config.beforeToolCall) { const beforeResult = await config.beforeToolCall( { assistantMessage, toolCall, args: validatedArgs, context }, signal, ); if (beforeResult?.block) { return { kind: "immediate", result: createErrorToolResult( beforeResult.reason || "Tool execution was blocked" ), isError: true, }; } } // 全部通过，返回"已准备好"的工具调用 return { kind: "prepared", toolCall, tool, args: validatedArgs }; } catch (error) { // 验证失败或钩子抛异常 → 转为 immediate 错误结果 return { kind: "immediate", result: createErrorToolResult( error instanceof Error ? error.message : String(error) ), isError: true, }; }
} 注意整个 prepare 体被 try-catch 包裹。这保证了不论是 validateToolArguments 抛出验证错误、还是 beforeToolCall 钩子意外崩溃，结果都是一个 immediate 错误 — 循环不会中断。 返回类型的设计也值得关注：PreparedToolCall | ImmediateToolCallOutcome。这是一个判别联合（discriminated union），用 kind 字段区分两种情况： kind: "prepared" — 验证通过，可以执行 kind: "immediate" — 验证失败，直接返回错误结果，跳过执行阶段 这个设计让调用者不需要 try-catch。检查 kind 就知道下一步该做什么。 prepareArguments 的用途 ：有些工具需要在验证之前预处理参数。比如 edit 工具需要把旧版 API 的 oldText/newText 顶层字段转换成新的 edits[] 数组格式。这个钩子允许工具自己做参数兼容性处理。 validateToolArguments 的作用 ：使用 TypeBox schema 做运行时验证。如果模型传了 { path: 123 } 而 schema 要求 path 是 string，验证会失败，循环返回一个清晰的错误信息给模型，模型有机会在下一轮修正。 beforeToolCall 钩子的位置选择 ：注意它在参数验证 之后 。这意味着钩子拿到的 args 是已验证的、类型安全的。钩子不需要自己做参数验证。同时，钩子可以访问完整的 context（包括之前的消息历史），这让基于上下文的安全策略成为可能 — 比如"如果模型在最近 3 轮内已经修改了 5 个文件，阻止进一步的写操作"。

