// packages/agent/src/agent.ts:112-143 class PendingMessageQueue { private messages: AgentMessage[] = []; constructor(public mode: QueueMode) {} enqueue(message: AgentMessage): void { this.messages.push(message); } drain(): AgentMessage[] { if (this.mode === "all") { const drained = this.messages.slice(); this.messages = []; return drained; } // "one-at-a-time" 模式 const first = this.messages[0]; if (!first) return []; this.messages = this.messages.slice(1); return [first]; }
} Agent 持有两个独立的消息队列： steeringQueue：agent.steer(msg) 入队，在 turn 间隙被消费 followUpQueue：agent.followUp(msg) 入队，在 agent 本来要退出时被消费 每个队列有两种 drain 模式： "all"：一次性取出所有排队的消息 "one-at-a-time"（默认）：一次只取一条，剩余的留到下次 为什么默认是 one-at-a-time？考虑这个场景：用户在 agent 执行 bash 命令时快速输入了三条 steering 消息。如果用 "all" 模式，三条消息会同时注入 context，LLM 需要一次理解三条指令。如果用 "one-at-a-time"，LLM 先处理第一条，在下一个 turn 间隙再收到第二条 — 就像人类对话中逐条回应，而不是一次性面对一堆请求。 队列和循环引擎的对接发生在 createLoopConfig() 中： // packages/agent/src/agent.ts:407-431（简化） private createLoopConfig(): AgentLoopConfig { return { // ... 其他字段 ... getSteeringMessages: async () => { return this.steeringQueue.drain(); }, getFollowUpMessages: async () => { return this.followUpQueue.drain(); }, };
} Agent 把队列的 drain() 方法包装成循环引擎需要的 getSteeringMessages 和 getFollowUpMessages 回调。循环引擎不知道消息从哪来 — 它只管调用回调取消息。

