): Promise<void> { const abortController = new AbortController(); let resolvePromise = () => {}; const promise = new Promise<void>((resolve) => { resolvePromise = resolve; }); this.activeRun = { promise, resolve: resolvePromise, abortController }; this._state.isStreaming = true; try { await executor(abortController.signal); } catch (error) { // 安全网：即使循环违反了"must not throw"契约， // Agent 也能合成一条失败消息而不是崩溃 await this.handleRunFailure( error, abortController.signal.aborted ); } finally { this.finishRun(); }
