会话格式经历了三个版本。向后兼容至关重要 — 用户的历史 session 文件不能因为升级 pi 而丢失。 v1：纯线性列表。 最早的版本没有 id 和 parentId，entry 按顺序排列，不支持分支。 v2：加入树形结构。 为每个 entry 生成 id，将前后关系转换成 parentId 链。 // packages/coding-agent/src/core/session-manager.ts:211-237 function migrateV1ToV2(entries: FileEntry[]): void { const ids = new Set<string>(); let prevId: string | null = null; for (const entry of entries) { if (entry.type === "session") { entry.version = 2; continue; } entry.id = generateId(ids); entry.parentId = prevId; prevId = entry.id; // 转换 compaction 的索引引用为 id 引用 if (entry.type === "compaction") { const comp = entry as CompactionEntry & { firstKeptEntryIndex?: number }; if (typeof comp.firstKeptEntryIndex === "number") { const targetEntry = entries[comp.firstKeptEntryIndex]; if (targetEntry && targetEntry.type !== "session") { comp.firstKeptEntryId = targetEntry.id; } delete comp.firstKeptEntryIndex; } } }
} 迁移逻辑很直接：遍历所有 entry，为每个生成唯一 id，parentId 指向前一个 entry（因为 v1 是线性的，所以父节点就是前一个）。特殊处理 CompactionEntry — v1 用数组索引（firstKeptEntryIndex）标记保留起点，v2 改用 entry id（firstKeptEntryId）。 v3：重命名 hookMessage → custom。 早期 extension 消息的角色名叫 hookMessage，v3 统一改为 custom。这是一个语义清理。 // packages/coding-agent/src/core/session-manager.ts:239-255 function migrateV2ToV3(entries: FileEntry[]): void { for (const entry of entries) { if (entry.type === "session") { entry.version = 3; continue; } if (entry.type === "message") { const msgEntry = entry as SessionMessageEntry; if (msgEntry.message && (msgEntry.message as { role: string }).role === "hookMessage") { (msgEntry.message as { role: string }).role = "custom"; } } }
} 所有迁移由 migrateToCurrentVersion() 统一调度，在 setSessionFile() 加载文件时自动执行。迁移是就地修改（mutate in place），修改后用 _rewriteFile() 重写整个文件。这意味着迁移是单向的、不可逆的 — 一旦文件被升级到 v3，旧版本的 pi 无法读取它。这是一个有意识的取舍：pi 的更新频率足够高，不需要支持降级。 // packages/coding-agent/src/core/session-manager.ts:261-271 function migrateToCurrentVersion(entries: FileEntry[]): boolean { const header = entries.find((e) => e.type === "session") as SessionHeader | undefined; const version = header?.version ?? 1; if (version >= CURRENT_SESSION_VERSION) return false; if (version < 2) migrateV1ToV2(entries); if (version < 3) migrateV2ToV3(entries); return true;
} 版本号采用递增整数（不是 semver），迁移链是线性的。加新版本时，只需在末尾加一个 if (version < N) migrateVN_1ToVN(entries)。这种"梯级迁移"模式简单、可组合、不容易出错。

