pi 用两种方式估算 context 占用量。首先，如果最近的 assistant 消息有 usage 字段（来自 API 的真实 token 统计），直接用它： // packages/coding-agent/src/core/compaction/compaction.ts:135-137 function calculateContextTokens(usage: Usage): number { return usage.totalTokens || usage.input + usage.output + usage.cacheRead + usage.cacheWrite;
} 但如果最近的 assistant 消息之后又追加了新消息（比如用户的新输入），这些新消息没有 usage 数据。pi 对这些"尾部消息"使用 chars/4 的启发式估算： // packages/coding-agent/src/core/compaction/compaction.ts:232-249（简化） function estimateTokens(message: AgentMessage): number { let chars = 0; switch (message.role) { case "user": { // 提取 text content 长度 chars = /* text content length */; return Math.ceil(chars / 4); } case "assistant": { // 累加 text + thinking + toolCall 长度 for (const block of message.content) { if (block.type === "text") chars += block.text.length; else if (block.type === "thinking") chars += block.thinking.length; else if (block.type === "toolCall") chars += block.name.length + JSON.stringify(block.arguments).length; } return Math.ceil(chars / 4); } // ... toolResult, bashExecution 等同理 }
} chars/4 是一个保守的启发式（偏向高估 token 数量）。宁可提前触发压缩，也不要因为低估而撞上 context window 的硬限制。对于图片消息，固定按 1200 token 估算。 estimateContextTokens 将两种策略组合：用最后一条有 usage 的 assistant 消息的真实 token 数，加上之后所有消息的启发式估算： // packages/coding-agent/src/core/compaction/compaction.ts:186-214（简化） function estimateContextTokens(messages: AgentMessage[]): ContextUsageEstimate { const usageInfo = getLastAssistantUsageInfo(messages); if (!usageInfo) { // 没有任何 usage 数据，全部用启发式 let estimated = 0; for (const message of messages) estimated += estimateTokens(message); return { tokens: estimated, usageTokens: 0, trailingTokens: estimated }; } const usageTokens = calculateContextTokens(usageInfo.usage); let trailingTokens = 0; for (let i = usageInfo.index + 1; i < messages.length; i++) { trailingTokens += estimateTokens(messages[i]); } return { tokens: usageTokens + trailingTokens, usageTokens, trailingTokens };
}

