// extensions/types.ts:986-1026（节选 5 个关键事件）
export interface ExtensionAPI { on(event: "session_start", handler: ExtensionHandler<SessionStartEvent>): void; on(event: "context", handler: ExtensionHandler<ContextEvent, ContextEventResult>): void; on(event: "tool_call", handler: ExtensionHandler<ToolCallEvent, ToolCallEventResult>): void; on(event: "tool_result", handler: ExtensionHandler<ToolResultEvent, ToolResultEventResult>): void; on(event: "input", handler: ExtensionHandler<InputEvent, InputEventResult>): void; // ... 共 26 种事件
} 事件系统的设计有两层含义。 观察型事件 （如 session_start、agent_end、message_update）让 extension 被动获知系统状态变化。 干预型事件 （如 tool_call、input、context）通过返回值影响系统行为 — tool_call 可以 block 工具执行，input 可以 transform 用户输入，context 可以修改发送给 LLM 的消息列表。 这个区分体现在 handler 的泛型签名中： // extensions/types.ts:981
export type ExtensionHandler<E, R = undefined> = (event: E, ctx: ExtensionContext) => Promise<R | void> | R | void; 当 R = undefined 时，handler 是纯观察型 — 返回值被忽略。当 R 是具体类型时（如 ToolCallEventResult），handler 可以通过返回值干预流程。

