// extensions/loader.ts:373-390
export async function loadExtensions( paths: string[], cwd: string, eventBus?: EventBus
): Promise<LoadExtensionsResult> { const extensions: Extension[] = []; const errors: Array<{ path: string; error: string }> = []; const runtime = createExtensionRuntime(); for (const extPath of paths) { const { extension, error } = await loadExtension(extPath, cwd, resolvedEventBus, runtime); if (error) { errors.push({ path: extPath, error }); continue; } if (extension) { extensions.push(extension); } } return { extensions, errors, runtime };
} Loader 的关键设计： 串行加载 。Extension 按配置顺序逐个加载，不并行。这保证了注册顺序的确定性 — 先加载的 extension 的事件 handler 先执行。 jiti 动态导入 。Extension 是普通的 TypeScript 文件，通过 @mariozechner/jiti（一个 fork 版本，支持 virtualModules）在运行时编译和加载。这意味着 extension 不需要预编译。 Virtual Modules 。编译后的 Bun binary 中没有 node_modules，extension 依赖的包通过 virtualModules 映射到 binary 中打包的静态导入： // extensions/loader.ts:43-50
const VIRTUAL_MODULES: Record<string, unknown> = { "@sinclair/typebox": _bundledTypebox, "@mariozechner/pi-agent-core": _bundledPiAgentCore, "@mariozechner/pi-tui": _bundledPiTui, "@mariozechner/pi-ai": _bundledPiAi, "@mariozechner/pi-coding-agent": _bundledPiCodingAgent,
}; 这些 import 必须是静态的（import * as），否则 Bun 不会打包。这是一个不太常见的"静态依赖支撑动态加载"的模式。

