function loadProjectContextFiles(options: { cwd?: string }) { const contextFiles = []; // 1. 先加载全局上下文（~/.pi/agent/ 下的 AGENTS.md） const globalContext = loadContextFileFromDir(resolvedAgentDir); if (globalContext) contextFiles.push(globalContext); // 2. 从当前目录向上遍历到根目录 let currentDir = resolvedCwd; while (true) { const contextFile = loadContextFileFromDir(currentDir); if (contextFile) ancestorContextFiles.unshift(contextFile); if (currentDir === root) break; currentDir = resolve(currentDir, ".."); } // 3. 按从根到当前目录的顺序返回 contextFiles.push(...ancestorContextFiles); return contextFiles;
