// file: packages/coding-agent/src/core/model-registry.ts:332-362
private loadBuiltInModels( overrides: Map<string, ProviderOverride>, modelOverrides: Map<string, Map<string, ModelOverride>>,
): Model<Api>[] { return getProviders().flatMap((provider) => { const models = getModels(provider as KnownProvider); const providerOverride = overrides.get(provider); const perModelOverrides = modelOverrides.get(provider); return models.map((m) => { let model = m; // Provider-level 覆盖 (baseUrl, compat) if (providerOverride) { model = { ...model, baseUrl: providerOverride.baseUrl ?? model.baseUrl, compat: mergeCompat(model.compat, providerOverride.compat), }; } // Per-model 覆盖 const modelOverride = perModelOverrides?.get(m.id); if (modelOverride) { model = applyModelOverride(model, modelOverride); } return model; }); });
} 这段代码揭示了覆盖的两个层次： Provider-level 覆盖 ：影响一个 provider 下的所有模型。比如你可以把 Anthropic 的 baseUrl 改成代理地址，所有 Anthropic 模型都会使用新地址。 Per-model 覆盖 ：只影响特定模型。比如你可以单独修改 claude-opus-4-6 的 maxTokens 而不影响其他 Anthropic 模型。

