// file: packages/coding-agent/src/core/model-registry.ts:365-376
private mergeCustomModels(builtInModels: Model<Api>[], customModels: Model<Api>[]): Model<Api>[] { const merged = [...builtInModels]; for (const customModel of customModels) { const existingIndex = merged.findIndex( (m) => m.provider === customModel.provider && m.id === customModel.id ); if (existingIndex >= 0) { merged[existingIndex] = customModel; // 自定义覆盖内建 } else { merged.push(customModel); // 新增自定义模型 } } return merged;
} 合并逻辑简洁明了：按 provider + id 匹配。如果自定义模型的 provider 和 id 与内建模型相同，完全替换；否则追加。

