Model 类型中有一个 compat 字段，它是 Model Registry 中最复杂的部分： // file: packages/coding-agent/src/core/model-registry.ts:50-80
const OpenAICompletionsCompatSchema = Type.Object({ supportsStore: Type.Optional(Type.Boolean()), supportsDeveloperRole: Type.Optional(Type.Boolean()), supportsReasoningEffort: Type.Optional(Type.Boolean()), reasoningEffortMap: Type.Optional(ReasoningEffortMapSchema), maxTokensField: Type.Optional(Type.Union([ Type.Literal("max_completion_tokens"), Type.Literal("max_tokens") ])), thinkingFormat: Type.Optional(Type.Union([ Type.Literal("openai"), Type.Literal("openrouter"), Type.Literal("zai"), Type.Literal("qwen"), Type.Literal("qwen-chat-template"), ])), openRouterRouting: Type.Optional(OpenRouterRoutingSchema), // ... 更多字段
