): AgentTool<any, TDetails> { return { name: definition.name, label: definition.label, description: definition.description, parameters: definition.parameters, prepareArguments: definition.prepareArguments, execute: (toolCallId, params, signal, onUpdate) => definition.execute( toolCallId, params, signal, onUpdate, ctxFactory?.() as ExtensionContext ), };
