当 LLM 在 parallel 模式下同时发起多个 edit 调用（比如"同时修改 3 个文件"），可能有两个 edit 操作指向同一个文件。file-mutation-queue 确保同一个文件的写操作被串行化： // packages/coding-agent/src/core/tools/file-mutation-queue.ts:1-39 const fileMutationQueues = new Map<string, Promise<void>>(); function getMutationQueueKey(filePath: string): string { const resolvedPath = resolve(filePath); try { return realpathSync.native(resolvedPath); // 解析符号链接 } catch { return resolvedPath; }
} export async function withFileMutationQueue<T>( filePath: string, fn: () => Promise<T>,
): Promise<T> { const key = getMutationQueueKey(filePath); const currentQueue = fileMutationQueues.get(key) ?? Promise.resolve(); let releaseNext!: () => void; const nextQueue = new Promise<void>((resolve) => { releaseNext = resolve; }); const chainedQueue = currentQueue.then(() => nextQueue); fileMutationQueues.set(key, chainedQueue); await currentQueue; // 等前一个操作完成 try { return await fn(); // 执行本次操作 } finally { releaseNext(); // 释放锁，让下一个操作开始 if (fileMutationQueues.get(key) === chainedQueue) { fileMutationQueues.delete(key); // 清理：没有后续排队时删除条目 } }
} 这 39 行代码是整个 file-mutation-queue.ts 的全部。设计要点： 基于 Promise 链的无锁串行化 — 不用 mutex，用 Promise 的 .then() 链来排队 realpathSync.native 解析符号链接 — 确保 ./src/foo.ts 和 ../project/src/foo.ts 如果指向同一个文件，用同一个锁 自动清理 — 当没有后续操作排队时删除 Map 条目，避免内存泄漏 不同文件仍然并行 — 只有指向同一文件的操作才串行

