// packages/coding-agent/src/core/tools/bash.ts:69-127
export function createLocalBashOperations(): BashOperations { return { exec: (command, cwd, { onData, signal, timeout, env }) => { return new Promise((resolve, reject) => { const { shell, args } = getShellConfig(); if (!existsSync(cwd)) { reject(new Error( `Working directory does not exist: ${cwd}` )); return; } const child = spawn(shell, [...args, command], { cwd, detached: true, env: env ?? getShellEnv(), stdio: ["ignore", "pipe", "pipe"], }); // Stream stdout and stderr child.stdout?.on("data", onData); child.stderr?.on("data", onData); // ...timeout and abort handling... }); }, };
} 几个关键实现细节： detached: true 。创建独立的进程组，这样 killProcessTree 可以一次性杀掉主进程和它所有的子进程。没有这个选项，kill 主进程后子进程可能变成孤儿进程继续运行。 stdio: ["ignore", "pipe", "pipe"] 。stdin 被忽略（LLM 不需要和命令交互），stdout 和 stderr 都被 pipe 出来通过 onData 回调传递。注意 stdout 和 stderr 合并到了同一个 onData — 这意味着输出顺序和终端中看到的一致，但没有办法区分标准输出和错误输出。 工作目录校验 。在 spawn 之前检查 cwd 是否存在。这避免了一个常见的 debug 陷阱 — 如果工作目录不存在，spawn 会报一个含糊的错误，不如直接给出明确的错误信息。

