// packages/tui/src/tui.ts:469-516
requestRender(force = false): void { if (force) { this.previousLines = []; this.previousWidth = -1; this.previousHeight = -1; // ...重置所有状态... process.nextTick(() => { this.doRender(); }); return; } if (this.renderRequested) return; this.renderRequested = true; process.nextTick(() => this.scheduleRender());
} private scheduleRender(): void { const elapsed = performance.now() - this.lastRenderAt; const delay = Math.max(0, MIN_RENDER_INTERVAL_MS - elapsed); this.renderTimer = setTimeout(() => { this.doRender(); }, delay);
} requestRender 有两种模式： force = true ：清空所有缓存，下一个 tick 立即全量渲染。用于主题切换、终端 reset 等场景。 force = false （默认）：标记"需要渲染"，通过 scheduleRender 节流到至少 16ms 间隔。多次快速的 requestRender 调用只会触发一次实际渲染。 process.nextTick 确保渲染在当前事件循环结束后执行 — 这让同一个 tick 中的多个状态变更可以合并为一次渲染。

