Slack 有 40000 字符的消息长度限制。mom 通过 splitForSlack 自动分割长消息： // packages/mom/src/agent.ts:623-637
const SLACK_MAX_LENGTH = 40000;
const splitForSlack = (text: string): string[] => { if (text.length <= SLACK_MAX_LENGTH) return [text]; const parts: string[] = []; let remaining = text; let partNum = 1; while (remaining.length > 0) { const chunk = remaining.substring(0, SLACK_MAX_LENGTH - 50); remaining = remaining.substring(SLACK_MAX_LENGTH - 50); const suffix = remaining.length > 0 ? `\n_(continued ${partNum}...)_` : ""; parts.push(chunk + suffix); partNum++; } return parts;
};

