mom 的推荐部署方式是 Docker sandbox — 所有 bash 命令在容器中执行，限制了 agent 的文件系统访问。 sandbox 的抽象层很薄，只有一个 Executor 接口： // packages/mom/src/sandbox.ts:79-91
export interface Executor { exec(command: string, options?: ExecOptions): Promise<ExecResult>; getWorkspacePath(hostPath: string): string;
} 两个实现： // packages/mom/src/sandbox.ts:104-193
class HostExecutor implements Executor { async exec(command: string, options?: ExecOptions): Promise<ExecResult> { // 直接在 host 上执行 sh -c command const child = spawn(shell, [...shellArgs, command], { detached: true, stdio: ["ignore", "pipe", "pipe"], }); // ... timeout + abort signal 处理 } getWorkspacePath(hostPath: string): string { return hostPath; // host 路径不需要转换 }
} class DockerExecutor implements Executor { constructor(private container: string) {} async exec(command: string, options?: ExecOptions): Promise<ExecResult> { // 包装为 docker exec container sh -c 'command' const dockerCmd = `docker exec ${this.container} sh -c ${ shellEscape(command)}`; const hostExecutor = new HostExecutor(); return hostExecutor.exec(dockerCmd, options); } getWorkspacePath(_hostPath: string): string { return "/workspace"; // 容器内统一为 /workspace }
} DockerExecutor 的实现是委托模式 — 它把命令包装成 docker exec，然后交给 HostExecutor 执行。关键的安全边界在于： 路径隔离 。容器内只看到 /workspace（挂载的数据目录），看不到 host 文件系统 路径转换 。getWorkspacePath() 把 host 路径转为容器路径；translateToHostPath() 做反向转换（用于文件上传） 启动前验证 。validateSandbox() 检查 Docker 可用性和容器运行状态

