export interface ImmediateEvent { type: "immediate"; channelId: string; text: string;
} export interface OneShotEvent { type: "one-shot"; channelId: string; text: string; at: string; // ISO 8601 时间
} export interface PeriodicEvent { type: "periodic"; channelId: string; text: string; schedule: string; // cron 语法 timezone: string; // IANA 时区
} 三种事件类型覆盖了不同场景： Immediate ：脚本或 webhook 触发的即时事件（"新 GitHub issue 开了"） One-shot ：定时提醒（"下午 3 点提醒开会"） Periodic ：定期任务（"每天早上 9 点检查邮箱"） 事件以 JSON 文件形式存放在 events/ 目录中。EventsWatcher 用 fs.watch 监控目录变化，用 croner 库处理 cron 调度。agent 自己可以通过 bash 工具创建事件文件 — 这是一个优雅的自举设计：agent 的"安排未来行动"能力不需要专门的 API，只需要写文件。 periodic 事件还支持 [SILENT] 标记 — 如果定期检查发现没有可报告的内容，agent 回复 [SILENT]，mom 会删除状态消息，避免刷屏。

