pi 不内建 plan mode，但 transformContext 回调（第 8 章）可以实现它。 transformContext 在每次 LLM 调用前执行，可以修改发送给模型的消息列表。Plan mode 的本质就是"在不同阶段注入不同的指令"： 实现草图：transformContext 版 plan mode type PlanModeState = "planning" | "reviewing" | "executing"; function createPlanModeConfig( getState: () => PlanModeState, getPlan: () => string | null,
): Partial<AgentLoopConfig> { return { transformContext: (messages) => { const state = getState(); const plan = getPlan(); if (state === "planning") { // 注入计划指令：只输出计划，不调用工具 return [ ...messages, { role: "user", content: [{ type: "text", text: "[SYSTEM] 现在是规划阶段。" + "分析任务，输出详细的执行计划。" + "不要调用任何工具。" + "用编号列表格式输出计划步骤。" }], }, ]; } if (state === "executing" && plan) { // 注入已确认的计划作为执行指导 return [ ...messages, { role: "user", content: [{ type: "text", text: `[SYSTEM] 按以下计划逐步执行：\n${plan}\n` + "每完成一个步骤，报告进度后继续下一步。" }], }, ]; } return messages; // reviewing 阶段或无计划时不修改 }, // 在 planning 阶段禁止工具调用 beforeToolCall: async () => { if (getState() === "planning") { return { block: true, reason: "Planning phase - tools disabled" } } return undefined; }, };
} 使用方式： let state: PlanModeState = "planning";
let plan: string | null = null; const config = createPlanModeConfig( () => state, () => plan,
); // 阶段 1：生成计划
const planResult = await session.prompt("Fix the login bug", config);
// planResult 包含 agent 输出的计划文本 // 阶段 2：用户审阅（产品层实现确认 UI）
plan = extractPlanFromMessages(session.messages);
const confirmed = await userConfirm(plan); // 阶段 3：执行
if (confirmed) { state = "executing"; await session.prompt("Execute the plan", config);
}

