api-registry.ts 是整个 pi-ai 层的枢纽。它只有 98 行，是极简设计的范例。完整代码如下： // packages/ai/src/api-registry.ts:1-38（类型定义和状态） export type ApiStreamFunction = ( model: Model<Api>, context: Context, options?: StreamOptions,
) => AssistantMessageEventStream; export type ApiStreamSimpleFunction = ( model: Model<Api>, context: Context, options?: SimpleStreamOptions,
) => AssistantMessageEventStream; export interface ApiProvider< TApi extends Api = Api, TOptions extends StreamOptions = StreamOptions
> { api: TApi; stream: StreamFunction<TApi, TOptions>; streamSimple: StreamFunction<TApi, SimpleStreamOptions>;
} interface ApiProviderInternal { api: Api; stream: ApiStreamFunction; streamSimple: ApiStreamSimpleFunction;
} type RegisteredApiProvider = { provider: ApiProviderInternal; sourceId?: string;
}; const apiProviderRegistry = new Map<string, RegisteredApiProvider>(); // packages/ai/src/api-registry.ts:66-98（公共 API） export function registerApiProvider<TApi extends Api, TOptions extends StreamOptions>( provider: ApiProvider<TApi, TOptions>, sourceId?: string,
): void { apiProviderRegistry.set(provider.api, { provider: { api: provider.api, stream: wrapStream(provider.api, provider.stream), streamSimple: wrapStreamSimple(provider.api, provider.streamSimple), }, sourceId, });
} export function getApiProvider(api: Api) { return apiProviderRegistry.get(api)?.provider;
} export function getApiProviders(): ApiProviderInternal[] { return Array.from(apiProviderRegistry.values(), (entry) => entry.provider);
} export function unregisterApiProviders(sourceId: string): void { for (const [api, entry] of apiProviderRegistry.entries()) { if (entry.sourceId === sourceId) { apiProviderRegistry.delete(api); } }
} export function clearApiProviders(): void { apiProviderRegistry.clear();
} 整个注册表的 API 面只有五个函数：registerApiProvider（注册）、getApiProvider（查找单个）、getApiProviders（列出全部）、unregisterApiProviders（按 sourceId 批量注销）、clearApiProviders（清空，用于测试）。其中前四个是常用的。

