第二遍扫描的核心是一个状态机，追踪"当前有哪些待回复的 tool call"： // packages/ai/src/providers/transform-messages.ts:98-124 const result: Message[] = [];
let pendingToolCalls: ToolCall[] = [];
let existingToolResultIds = new Set<string>(); for (let i = 0; i < transformed.length; i++) { const msg = transformed[i]; if (msg.role === "assistant") { // If we have pending orphaned tool calls from a // previous assistant, insert synthetic results now if (pendingToolCalls.length > 0) { for (const tc of pendingToolCalls) { if (!existingToolResultIds.has(tc.id)) { result.push({ role: "toolResult", toolCallId: tc.id, toolName: tc.name, content: [{ type: "text", text: "No result provided" }], isError: true, timestamp: Date.now(), } as ToolResultMessage); } } pendingToolCalls = []; existingToolResultIds = new Set(); } 注意这里的时序：当遇到一条新的 assistant 消息时，如果前一条 assistant 还有未回复的 tool call，在新 assistant 之前 插入合成的 tool result。这保证了消息序列始终满足 assistant(tool_call) → toolResult → assistant 的交替模式。

